      id: row.ID ?? row.id,
      source: row.SOURCE ?? row.source,
      name: row.NAME ?? row.name ?? null,
      contact_email: row.CONTACT_EMAIL ?? row.contact_email ?? null,
      context: row.CONTEXT ?? row.context ?? null,
