// src/sprint-briefing/fetch-github.ts
async function fetchGithubSprintSignals(octokit, repos) {
  const chunks = [];
  for (const full of repos) {
    const [owner, repo] = full.trim().split("/");
    if (!owner || !repo) continue;
    try {
      const [openIssues, openPrs, mergedSince] = await Promise.all([
        octokit.rest.issues.listForRepo({ owner, repo, state: "open", per_page: 30, sort: "updated" }),
        octokit.rest.pulls.list({ owner, repo, state: "open", per_page: 20, sort: "updated" }),
        octokit.rest.pulls.list({
          owner,
          repo,
          state: "closed",
          per_page: 15,
          sort: "updated",
          direction: "desc"
        })
      ]);
      const window26h = Date.now() - 26 * 60 * 60 * 1e3;
      const since26hIso = new Date(window26h).toISOString();
      const mergedRecent = mergedSince.data.filter((p3) => {
        if (!p3.merged_at) return false;
        return new Date(p3.merged_at).getTime() > window26h;
      });
      chunks.push(`### GitHub ${owner}/${repo}`);
      try {
        const commitsRes = await octokit.rest.repos.listCommits({
          owner,
          repo,
          per_page: 15,
          since: since26hIso
        });
        const commits = commitsRes.data.filter((c6) => c6.commit.author?.date);
        chunks.push(
          `Recent commits (last 26h, ${commits.length} total):`,
          ...commits.length ? commits.slice(0, 10).map((c6) => {
            const author = c6.commit?.author;
            const d6 = (author?.date ?? "").slice(0, 16);
            const m4 = ((c6.commit?.message ?? "").split("\n")[0] ?? "").slice(0, 90);
            const a6 = author?.name ?? "unknown";
            return `- [${d6}] ${m4} (${a6})`;
          }) : ["- (no commits in window)"]
        );
      } catch {
        chunks.push("Recent commits: (fetch failed)");
      }
      chunks.push(
        `Open PRs (${openPrs.data.length}):`,
        ...openPrs.data.slice(0, 8).map((p3) => `- PR#${p3.number} ${p3.title} (${p3.head.ref})`)
      );
      chunks.push(
        `Merged last ~26h:`,
        ...mergedRecent.length ? mergedRecent.map((p3) => `- PR#${p3.number} ${p3.title}`) : ["- (none)"]
      );
      chunks.push(
        `Open issues (${openIssues.data.length} shown, most recently updated):`,
        ...openIssues.data.slice(0, 8).map(
          (i6) => `- #${i6.number} ${i6.title} [updated ${(i6.updated_at || "").slice(0, 10)}]`
        )
      );
      try {
        const runs = await octokit.rest.actions.listWorkflowRunsForRepo({
          owner,
          repo,
          per_page: 8,
          status: "completed"
        });
        const failed = runs.data.workflow_runs.filter((r6) => r6.conclusion === "failure").slice(0, 5);
        if (failed.length) {
          chunks.push(`Recent CI failures:`);
          chunks.push(...failed.map((r6) => `- ${r6.name}: ${r6.conclusion} (${r6.head_branch})`));
        }
      } catch {
      }
    } catch (e6) {
      chunks.push(`### GitHub ${full}: ERROR ${String(e6?.message || e6).slice(0, 200)}`);
    }
  }
  return chunks.join("\n");
}

// src/sprint-briefing/fetch-linear.ts
var LINEAR_API = "https://api.linear.app/graphql";
async function fetchLinearSprintSignals(apiKey, _teamId) {
  void _teamId;
  const query = `
    query SprintIssues {
      issues(
        filter: { state: { type: { nin: ["completed", "canceled"] } } }
        first: 40
      ) {
        nodes {
          identifier
          title
          priority
          updatedAt
          comments(first: 12) {
            nodes { body createdAt }
          }
        }
      }
    }
  `;
  try {
    const res = await fetch(LINEAR_API, {
      method: "POST",
      headers: {
        Authorization: apiKey,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ query })
    });
    const json = await res.json();
    if (json.errors?.length) {
      return `Linear API errors: ${json.errors.map((e6) => e6.message).join("; ")}`;
    }
    const nodes5 = json.data?.issues?.nodes ?? [];
    const lines = ["### Linear"];
    if (nodes5.length === 0) lines.push("- (no issues returned \u2014 check key / workspace)");
    for (const n3 of nodes5) {
      lines.push(`- ${n3.identifier} P${n3.priority ?? "?"}: ${n3.title} (${n3.updatedAt})`);
      const recentComments = n3.comments?.nodes?.filter((c6) => {
        const t2 = new Date(c6.createdAt).getTime();
        return Date.now() - t2 < 26 * 60 * 60 * 1e3;
      }) ?? [];
      for (const c6 of recentComments.slice(0, 3)) {
        lines.push(`  \xB7 comment: ${(c6.body || "").slice(0, 180).replace(/\s+/g, " ")}`);
      }
    }
    return lines.join("\n");
  } catch (e6) {
    return `Linear fetch failed: ${String(e6?.message || e6)}`;
  }
}

// src/sprint-briefing/synthesize.ts
var GROQ_MODEL = process.env.SPRINT_BRIEFING_GROQ_MODEL || "llama-3.3-70b-versatile";
var CLAUDE_MODEL = process.env.SPRINT_BRIEFING_CLAUDE_MODEL || "claude-sonnet-4-20250514";
async function clusterSignalsWithGroq(groq, rawDigest) {
  const prompt = `You are a delivery lead extracting STRUCTURED FACTS from raw sprint signals.

Return markdown sections:
1) Themes (3-7 bullets)
2) Blockers / risks
3) What changed since "yesterday" (infer from timestamps if present)
4) Stale items (no movement implied)
5) CI / merge highlights

RAW SIGNALS:
---
${rawDigest.slice(0, 12e4)}
---

Keep under 1200 words. Be factual \u2014 no invention.`;
  const completion = await groq.chat.completions.create({
    model: GROQ_MODEL,
    messages: [{ role: "user", content: prompt }],
    temperature: 0.2,
    max_tokens: 4096
  });
  const text = completion.choices[0]?.message?.content;
  return typeof text === "string" ? text : "";
}
async function writeBriefingNarrative(anthropic, clusterMarkdown, rawDigest) {
  const prompt = `Write a SPOKEN morning briefing for Elena Revicheva \u2014 a solo technical founder (3-5 minutes when read aloud).

HARD RULES \u2014 violating any of these is a critical failure:
1. ONLY reference facts that appear in the CLUSTER or RAW below. Zero invention. Zero filler.
2. If commits are present \u2014 name them specifically (repo name + commit message). This is the primary freshness signal.
3. If voice notes / diary / tasks are present \u2014 surface them explicitly at the start. These are Elena's own words from yesterday. They come first.
4. If a section has NO data (e.g. no commits, no tasks) \u2014 say so briefly and move on. Do NOT pad with generalities.
5. Start with voice notes and personal context if present, then GitHub activity, then focus suggestion.
6. End with ONE concrete action she can take in the next 2 hours based on what actually happened.

FORMAT:
- Conversational, direct. Spoken out loud. No markdown in output \u2014 plain sentences only.
- Start: "Good morning Elena. Here's what actually happened while you were offline."
- Sections: personal notes first \u2192 repo activity (commits, PRs) \u2192 one focus action.

CLUSTER (Groq-structured facts):
${clusterMarkdown}

RAW SIGNALS (live data \u2014 use these):
${rawDigest.slice(0, 6e4)}
`;
  const msg = await anthropic.messages.create({
    model: CLAUDE_MODEL,
    max_tokens: 8192,
    messages: [{ role: "user", content: prompt }]
  });
  const block = msg.content[0];
  return block && block.type === "text" ? block.text : "";
}

// src/sprint-briefing/tts-openai.ts
async function synthesizeBriefingMp3(openai, narrativePlainText) {
  const voice = process.env.SPRINT_BRIEFING_TTS_VOICE || "nova";
  const trimmed = narrativePlainText.slice(0, 4096);
  const res = await openai.audio.speech.create({
    model: process.env.SPRINT_BRIEFING_TTS_MODEL || "tts-1",
    voice,
    input: trimmed,
    response_format: "mp3"
  });
  const arr = await res.arrayBuffer();
  return Buffer.from(arr);
}

